Used sliding window with three pointers algorithm:

    class Solution {

        public static void main(String[] args) {
            System.out.println(getSubArrayCount(new int[] {1, 2, 1, 1}, 2)); //2
            System.out.println(getSubArrayCount(new int[] {1, 2, 3, 4, 1, 2, 5}, 3)); //10
            System.out.println(getSubArrayCount(new int[] {1, 2, 2, 5, 4, 1}, 3)); //3
            System.out.println(getSubArrayCount(new int[] {1, 5, 4, 4, 2}, 2)); //4
            System.out.println(getSubArrayCount(new int[] {1, 1, 2, 2, 3, 3, 4}, 2)); //3
            System.out.println(getSubArrayCount(new int[] {1, 2, 3, 1, 1, 1, 1, 1, 1}, 2)); //5
        }

        public static int getSubArrayCount(int[] nums, int k) {
            Set<Integer> set = new HashSet<>();
            int left = 0, right = 0;
            int count = 0;

            while (right < nums.length) {
                if (!set.add(nums[right])) {
                    while (nums[left] != nums[right]) {
                        set.remove(nums[left]);
                        left++;
                    }
                    left++;
                }

                int nearLeft = left;
                while (right - nearLeft + 1 >= k) {
                    count++;
                    nearLeft++;
                }

                right++;
            }

            return count;
        }
    }

