	private static int helper(int[] nums, int k) {
		Map<Integer, Integer> map = new HashMap<>();
               int left=0, right=0;
               int count=0;
		for (left = 0; left < nums.length; ) {
			while (right < nums.length) {
				map.put(nums[right], map.getOrDefault(nums[right], 0) + 1);
				// count hashmap has unique values one
				int newCount = (int) map.entrySet().stream().filter(i -> i.getValue() == 1).count();
				if (newCount >= k) {
					count++;
				}
				right++;
			}
			map.clear();
			right=++left;
		}

        return count;
	}
